"use strict";const t=require("./account.js");exports.ensureBackendAccount=async function(e){const r=await t.ensureAuthenticated(e);return{user:r.user,isNew:Boolean(r.isNew)}},exports.fetchBackendProfile=async function(){return t.fetchCurrentUser().catch(()=>null)},exports.loadBackendAuthState=function(){const e=t.loadAuthState();return e?{userId:e.userId,nickname:String(e.nickname||"").trim(),avatarUrl:String(e.avatarUrl||"").trim(),updatedAt:Number(e.updatedAt||Date.now())}:null},exports.saveBackendAuthState=function(e){const r=t.loadAuthState();r&&t.saveAuthState({token:r.token,refreshToken:r.refreshToken,expiresIn:Math.max(0,Math.floor((r.expiresAt-Date.now())/1e3)),user:{userId:String(e.userId||r.userId||"").trim(),nickname:String(e.nickname||r.nickname||"").trim(),avatarUrl:String(e.avatarUrl||r.avatarUrl||"").trim(),createdAt:Number(e.createdAt||Date.now()),updatedAt:Number(e.updatedAt||Date.now()),lastLoginAt:Number(e.lastLoginAt||Date.now())}})},exports.updateBackendProfileByPayload=async function(e){return t.loadAuthState()?{user:await t.updateCurrentUserProfile(e).catch(()=>null),isNew:!1}:{user:t.buildUserProfileFromAuth(),isNew:!1}};
